import { createSlice, createAsyncThunk } from '@reduxjs/toolkit';
import { pointAPI } from '../../api/api';

export const checkPoint = createAsyncThunk(
  'points/check',
  async ({ x, y, r }, { rejectWithValue }) => {
    try {
      const result = await pointAPI.checkPoint(x, y, r);
      if (result.success) {
        return result.data;
      } else {
        return rejectWithValue(result.message);
      }
    } catch (error) {
      return rejectWithValue('Ошибка проверки точки');
    }
  }
);

export const fetchPoints = createAsyncThunk(
  'points/fetch',
  async (_, { rejectWithValue }) => {
    try {
      const result = await pointAPI.getResults();
      if (result.success) {
        return result.data;
      } else {
        return rejectWithValue(result.message);
      }
    } catch (error) {
      return rejectWithValue('Ошибка загрузки результатов');
    }
  }
);

export const clearPoints = createAsyncThunk(
  'points/clear',
  async (_, { rejectWithValue }) => {
    try {
      const result = await pointAPI.clearResults();
      if (result.success) {
        return [];
      } else {
        return rejectWithValue(result.message);
      }
    } catch (error) {
      return rejectWithValue('Ошибка очистки');
    }
  }
);

const pointsSlice = createSlice({
  name: 'points',
  initialState: {
    points: [],
    loading: false,
    error: null
  },
  reducers: {
    addPoint: (state, action) => {
      state.points.unshift(action.payload);
    }
  },
  extraReducers: (builder) => {
    builder
      .addCase(checkPoint.pending, (state) => {
        state.loading = true;
        state.error = null;
      })
      .addCase(checkPoint.fulfilled, (state, action) => {
        state.loading = false;
        state.points.unshift(action.payload);
      })
      .addCase(checkPoint.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload;
      })
      .addCase(fetchPoints.fulfilled, (state, action) => {
        state.points = action.payload;
      })
      .addCase(clearPoints.fulfilled, (state) => {
        state.points = [];
      });
  }
});

export const { addPoint } = pointsSlice.actions;
export default pointsSlice.reducer;
